import zipfile
import xml.etree.ElementTree as ET

def col_letter_to_index(letter):
    """将列字母转换为索引（A=0, B=1, ...）"""
    index = 0
    for char in letter:
        index = index * 26 + (ord(char) - ord('A') + 1)
    return index - 1

def parse_cell_ref(cell_ref):
    """解析单元格引用，如'B2' -> (col=1, row=1)"""
    col = ''
    row = ''
    for char in cell_ref:
        if char.isalpha():
            col += char
        else:
            row += char
    return (col_letter_to_index(col), int(row) - 1)

def get_shared_strings(z):
    """获取共享字符串表"""
    if 'xl/sharedStrings.xml' not in z.namelist():
        return []

    with z.open('xl/sharedStrings.xml') as f:
        tree = ET.parse(f)
        root = tree.getroot()
        ns = {'': 'http://schemas.openxmlformats.org/spreadsheetml/2006/main'}
        strings = []
        for si in root.findall('si', ns):
            t = si.find('t', ns)
            if t is not None and t.text:
                strings.append(t.text)
            else:
                strings.append('')
        return strings

def read_sheet_data(z, sheet_name, shared_strings):
    """读取工作表数据，返回二维数组"""
    with z.open(sheet_name) as f:
        tree = ET.parse(f)
        root = tree.getroot()

        ns = {'': 'http://schemas.openxmlformats.org/spreadsheetml/2006/main'}

        # 获取维度信息
        dimension = root.find('dimension', ns)
        if dimension is not None:
            ref = dimension.get('ref')
            print(f"数据范围: {ref}")

        # 获取所有行
        rows = root.findall('row', ns)
        print(f"总行数: {len(rows)}")

        # 找出最大行和最大列
        max_row = 0
        max_col = 0

        for row in rows:
            row_num = int(row.get('r'))
            if row_num > max_row:
                max_row = row_num

            cells = row.findall('c', ns)
            for cell in cells:
                cell_ref = cell.get('r')
                col, row_idx = parse_cell_ref(cell_ref)
                if col > max_col:
                    max_col = col

        print(f"最大行: {max_row}, 最大列: {max_col}")

        # 创建数据网格
        data = [['' for _ in range(max_col + 1)] for _ in range(max_row)]

        # 填充数据
        for row in rows:
            cells = row.findall('c', ns)
            for cell in cells:
                cell_ref = cell.get('r')
                cell_type = cell.get('t')
                col, row_idx = parse_cell_ref(cell_ref)

                v_elem = cell.find('v', ns)
                if v_elem is not None and v_elem.text:
                    val = v_elem.text

                    # 如果是共享字符串类型
                    if cell_type == 's':
                        idx = int(val)
                        if idx < len(shared_strings):
                            val = shared_strings[idx]

                    data[row_idx][col] = val

        return data

def print_table(data):
    """打印表格"""
    if not data:
        print("(空数据)")
        return

    # 计算每列最大宽度
    col_widths = [0] * len(data[0])
    for row in data:
        for i, cell in enumerate(row):
            if i < len(col_widths):
                cell_str = str(cell) if cell else ''
                if len(cell_str) > col_widths[i]:
                    col_widths[i] = min(len(cell_str), 50)  # 限制最大宽度

    for i, row in enumerate(data):
        row_str = '  '.join(f"{str(cell)[:50]:<{col_widths[j]}}" for j, cell in enumerate(row))
        print(f"{i+1:3d}: {row_str}")

try:
    with zipfile.ZipFile('/root/.openclaw/media/inbound/923dcee7-788e-4d49-9bbd-d0d2e751803f.xlsx', 'r') as z:
        # 获取共享字符串
        shared_strings = get_shared_strings(z)
        print(f"共享字符串数量: {len(shared_strings)}\n")

        # 读取所有工作表
        sheet_files = [
            ('xl/worksheets/sheet1.xml', '工作表1'),
            ('xl/worksheets/sheet2.xml', '工作表2'),
            ('xl/worksheets/sheet3.xml', '工作表3'),
        ]

        for sheet_file, sheet_name in sheet_files:
            if sheet_file in z.namelist():
                print(f"\n{'='*80}")
                print(f"{sheet_name}")
                print(f"{'='*80}")

                data = read_sheet_data(z, sheet_file, shared_strings)
                print_table(data)

except Exception as e:
    print(f'错误: {e}')
    import traceback
    traceback.print_exc()
